#include <stdio.h>
#include <stdlib.h>

int findRowWithMaxOnes(int n, int m, int **mat) {
    int bestRow = -1;
    int maxOnes = 0;
    int i = 0, j = m - 1;
    while (i < n && j >= 0) {
        if (mat[i][j] == 1) {
            int ones = j + 1; // all columns 0..j are 1
            if (ones > maxOnes) {
                maxOnes = ones;
                bestRow = i;
            }
            j--; // try to find more 1s in the same row
        } else {
            i++; // move to next row
        }
    }
    return bestRow;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **mat = (int**)malloc(n * sizeof(int*));
        for (int r = 0; r < n; ++r) {
            mat[r] = (int*)malloc(m * sizeof(int));
            for (int c = 0; c < m; ++c) {
                scanf("%d", &mat[r][c]);
            }
        }
        int ans = findRowWithMaxOnes(n, m, mat);
        printf("%d\n", ans);
        for (int r = 0; r < n; ++r) free(mat[r]);
        free(mat);
    }
    return 0;
}

